+
   Value *Div, *Rem;
   APInt C1, C2;
   if (!LHS->hasOneUse() || !MatchMul(LHS, Div, C1))
@@ -1207,7 +1208,22 @@ Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
         Builder.CreateMul(Div, ConstantInt::get(X->getType(), NewC)), MulXC2);
   }

+  // Handle case: (X >> C) + (X & (2^C - 1)) -> add nuw nsw (X >> C), (X & (2^C - 1))
+  // This occurs when adding quotient and remainder of unsigned division by power of 2.
+  if (match(LHS, m_LShr(m_Value(X), m_APInt(C1))) &&
+      match(RHS, m_And(m_Specific(X), m_APInt(C2))) &&
+      C1.isPowerOf2() && C2.isIntN(C1.getLimitedValue()) &&
